class Solution:
    def isFascinating(self, n: int) -> bool:
        s = str(n) + str(2 * n) + str(3 * n)
        # Must not contain '0'
        if '0' in s:
            return False
        # Must contain digits 1..9 exactly once => length 9 and set equals {'1'..'9'}
        return len(s) == 9 and set(s) == set('123456789')
```

